import { sendEmail } from './resend-client';
import { adminEmail } from './env';

export type AdminNotifyInput = {
  subject: string;
  title: string;
  bodyHtml: string;
  idempotencyKey?: string;
  to?: string;
  from?: string;
};

/** Send an admin alert email via Resend. Non-fatal — returns false on failure. */
export async function notifyAdmin(input: AdminNotifyInput): Promise<boolean> {
  const to = input.to || adminEmail();
  if (!to) {
    console.error('notifyAdmin: no ADMIN_EMAIL or to address');
    return false;
  }

  const html = `
    <div style="font-family:Arial,sans-serif;line-height:1.6;color:#151515;max-width:620px;margin:0 auto;padding:24px">
      <h1 style="font-size:22px;margin:0 0 16px;color:#0C0C0A">${input.title}</h1>
      ${input.bodyHtml}
    </div>
  `;

  try {
    await sendEmail({
      to,
      subject: input.subject,
      html,
      from: input.from,
    });
    return true;
  } catch (err) {
    console.error('notifyAdmin failed:', err);
    return false;
  }
}
