"use client";

import { usePathname } from "next/navigation";
import Link from "next/link";
import { useUser, UserButton } from "@clerk/nextjs";
import { useState, type ReactNode, type ComponentType } from "react";

export interface NavItem {
  label: string;
  href: string;
  icon: ComponentType<{ className?: string; style?: React.CSSProperties }>;
}

export interface PortalLayoutProps {
  portalName: string;
  logoSrc: string;
  brandColor: string;
  accentColor: string;
  navItems: NavItem[];
  adminNavItems?: NavItem[];
  mobileNavStyle?: "bottom" | "sheet";
  children: ReactNode;
}

const ADMIN_ROLES = ["Officer", "Admin"];

export function PortalLayout({
  portalName,
  logoSrc,
  brandColor,
  accentColor,
  navItems,
  adminNavItems = [],
  mobileNavStyle = "bottom",
  children,
}: PortalLayoutProps) {
  const pathname = usePathname();
  const { user } = useUser();
  const [sheetOpen, setSheetOpen] = useState(false);

  const role = user?.publicMetadata?.role as string | undefined;
  const isAdmin = role ? ADMIN_ROLES.includes(role) : false;
  const visibleNav = [...navItems, ...(isAdmin ? adminNavItems : [])];

  const isActive = (href: string) =>
    href === "/" ? pathname === "/" : pathname.startsWith(href);

  return (
    <>
      <style>{`
        .pl-root {
          display: flex;
          min-height: 100vh;
          min-height: 100dvh;
          background-color: var(--color-bg, #0f0f12);
          color: var(--color-text, #f5f5f5);
          font-family: var(--font-body, 'Inter', sans-serif);
        }

        /* ── Sidebar (desktop) ── */
        .pl-sidebar {
          width: 240px;
          flex-shrink: 0;
          display: flex;
          flex-direction: column;
          background-color: var(--color-surface, #1a1a22);
          border-right: 1px solid rgba(255,255,255,0.06);
          position: sticky;
          top: 0;
          height: 100vh;
          overflow-y: auto;
        }
        .pl-sidebar-header {
          display: flex;
          align-items: center;
          gap: var(--space-3, 12px);
          padding: var(--space-6, 24px) var(--space-4, 16px) var(--space-4, 16px);
          border-bottom: 1px solid rgba(255,255,255,0.06);
        }
        .pl-sidebar-logo {
          width: 32px;
          height: 32px;
          object-fit: contain;
          border-radius: var(--radius-sm, 4px);
        }
        .pl-sidebar-name {
          font-weight: 700;
          font-size: 0.95rem;
          color: var(--color-text, #f5f5f5);
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }
        .pl-nav {
          flex: 1;
          padding: var(--space-4, 16px) var(--space-2, 8px);
          display: flex;
          flex-direction: column;
          gap: var(--space-1, 4px);
        }
        .pl-nav-section-label {
          padding: var(--space-3, 12px) var(--space-3, 12px) var(--space-1, 4px);
          font-size: 0.7rem;
          font-weight: 600;
          letter-spacing: 0.08em;
          text-transform: uppercase;
          color: var(--color-text-muted, #888);
        }
        .pl-nav-link {
          display: flex;
          align-items: center;
          gap: var(--space-3, 12px);
          padding: var(--space-2, 8px) var(--space-3, 12px);
          border-radius: var(--radius-md, 8px);
          text-decoration: none;
          font-size: 0.9rem;
          color: var(--color-text-muted, #888);
          transition: background 0.15s, color 0.15s;
        }
        .pl-nav-link:hover {
          background-color: rgba(255,255,255,0.06);
          color: var(--color-text, #f5f5f5);
        }
        .pl-nav-link.active {
          color: var(--color-text, #f5f5f5);
          font-weight: 600;
        }
        .pl-nav-icon {
          width: 18px;
          height: 18px;
          flex-shrink: 0;
        }
        .pl-sidebar-footer {
          padding: var(--space-4, 16px);
          border-top: 1px solid rgba(255,255,255,0.06);
          display: flex;
          align-items: center;
          gap: var(--space-3, 12px);
        }
        .pl-user-name {
          font-size: 0.85rem;
          color: var(--color-text, #f5f5f5);
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }

        /* ── Main content ── */
        .pl-main {
          flex: 1;
          display: flex;
          flex-direction: column;
          overflow: hidden;
        }
        .pl-content {
          flex: 1;
          padding: var(--space-8, 32px);
          overflow-y: auto;
        }

        /* ── Mobile: hamburger header ── */
        .pl-mobile-header {
          display: none;
          align-items: center;
          justify-content: space-between;
          padding: var(--space-4, 16px);
          background-color: var(--color-surface, #1a1a22);
          border-bottom: 1px solid rgba(255,255,255,0.06);
          position: sticky;
          top: 0;
          z-index: 40;
        }
        .pl-mobile-header-brand {
          display: flex;
          align-items: center;
          gap: var(--space-2, 8px);
        }
        .pl-mobile-logo {
          width: 28px;
          height: 28px;
          object-fit: contain;
        }
        .pl-hamburger {
          background: none;
          border: none;
          cursor: pointer;
          padding: var(--space-2, 8px);
          color: var(--color-text, #f5f5f5);
          display: flex;
          flex-direction: column;
          gap: 5px;
        }
        .pl-hamburger span {
          display: block;
          width: 22px;
          height: 2px;
          background: currentColor;
          border-radius: 2px;
        }

        /* ── Sheet drawer (mobile) ── */
        .pl-sheet-overlay {
          position: fixed;
          inset: 0;
          background: rgba(0,0,0,0.6);
          z-index: 50;
        }
        .pl-sheet {
          position: fixed;
          top: 0;
          left: 0;
          bottom: 0;
          width: 260px;
          background-color: var(--color-surface, #1a1a22);
          z-index: 51;
          display: flex;
          flex-direction: column;
          overflow-y: auto;
        }

        /* ── Bottom nav (mobile) ── */
        .pl-bottom-nav {
          display: none;
          position: fixed;
          bottom: 0;
          left: 0;
          right: 0;
          background-color: var(--color-surface, #1a1a22);
          border-top: 1px solid rgba(255,255,255,0.06);
          z-index: 40;
          padding-bottom: env(safe-area-inset-bottom, 0);
        }
        .pl-bottom-nav-inner {
          display: flex;
          justify-content: space-around;
          align-items: center;
          height: 56px;
        }
        .pl-bottom-link {
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 2px;
          text-decoration: none;
          font-size: 0.65rem;
          color: var(--color-text-muted, #888);
          padding: var(--space-1, 4px) var(--space-2, 8px);
          flex: 1;
        }
        .pl-bottom-link.active {
          color: var(--color-text, #f5f5f5);
        }
        .pl-bottom-link svg, .pl-bottom-link .pl-nav-icon {
          width: 22px;
          height: 22px;
        }

        @media (max-width: 768px) {
          .pl-sidebar { display: none; }
          .pl-mobile-header { display: flex; }
          .pl-content { padding: var(--space-4, 16px); }
          .pl-bottom-nav-show { display: block; }
          .pl-content-bottom-pad { padding-bottom: 72px; }
        }
        @media (min-width: 769px) {
          .pl-sheet-overlay, .pl-sheet { display: none !important; }
          .pl-bottom-nav { display: none !important; }
        }
      `}</style>

      <div className="pl-root">
        {/* Desktop sidebar */}
        <aside className="pl-sidebar" style={{ "--brand": brandColor } as React.CSSProperties}>
          <div className="pl-sidebar-header">
            <img src={logoSrc} alt={`${portalName} logo`} className="pl-sidebar-logo" />
            <span className="pl-sidebar-name">{portalName}</span>
          </div>

          <nav className="pl-nav">
            {navItems.map((item) => (
              <NavLink key={item.href} item={item} active={isActive(item.href)} brandColor={brandColor} />
            ))}

            {isAdmin && adminNavItems.length > 0 && (
              <>
                <div className="pl-nav-section-label">Admin</div>
                {adminNavItems.map((item) => (
                  <NavLink key={item.href} item={item} active={isActive(item.href)} brandColor={brandColor} />
                ))}
              </>
            )}
          </nav>

          <div className="pl-sidebar-footer">
            <UserButton afterSignOutUrl="/login" />
            <span className="pl-user-name">
              {user?.firstName ?? user?.emailAddresses?.[0]?.emailAddress ?? ""}
            </span>
          </div>
        </aside>

        {/* Mobile sheet overlay */}
        {mobileNavStyle === "sheet" && sheetOpen && (
          <>
            <div className="pl-sheet-overlay" onClick={() => setSheetOpen(false)} />
            <div className="pl-sheet">
              <div className="pl-sidebar-header">
                <img src={logoSrc} alt="" className="pl-sidebar-logo" />
                <span className="pl-sidebar-name">{portalName}</span>
              </div>
              <nav className="pl-nav" onClick={() => setSheetOpen(false)}>
                {navItems.map((item) => (
                  <NavLink key={item.href} item={item} active={isActive(item.href)} brandColor={brandColor} />
                ))}
                {isAdmin && adminNavItems.length > 0 && (
                  <>
                    <div className="pl-nav-section-label">Admin</div>
                    {adminNavItems.map((item) => (
                      <NavLink key={item.href} item={item} active={isActive(item.href)} brandColor={brandColor} />
                    ))}
                  </>
                )}
              </nav>
              <div className="pl-sidebar-footer">
                <UserButton afterSignOutUrl="/login" />
                <span className="pl-user-name">
                  {user?.firstName ?? user?.emailAddresses?.[0]?.emailAddress ?? ""}
                </span>
              </div>
            </div>
          </>
        )}

        <div className="pl-main">
          {/* Mobile header */}
          <header className="pl-mobile-header">
            <div className="pl-mobile-header-brand">
              <img src={logoSrc} alt="" className="pl-mobile-logo" />
              <span style={{ fontWeight: 700, fontSize: "0.9rem" }}>{portalName}</span>
            </div>
            {mobileNavStyle === "sheet" && (
              <button className="pl-hamburger" onClick={() => setSheetOpen(true)} aria-label="Open menu">
                <span /><span /><span />
              </button>
            )}
            <UserButton afterSignOutUrl="/login" />
          </header>

          {/* Page content */}
          <main className={`pl-content${mobileNavStyle === "bottom" ? " pl-content-bottom-pad" : ""}`}>
            {children}
          </main>
        </div>

        {/* Mobile bottom nav */}
        {mobileNavStyle === "bottom" && (
          <nav className="pl-bottom-nav pl-bottom-nav-show">
            <div className="pl-bottom-nav-inner">
              {visibleNav.slice(0, 5).map((item) => {
                const Icon = item.icon;
                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className={`pl-bottom-link${isActive(item.href) ? " active" : ""}`}
                    style={isActive(item.href) ? { color: brandColor } : undefined}
                  >
                    <Icon className="pl-nav-icon" />
                    <span>{item.label}</span>
                  </Link>
                );
              })}
            </div>
          </nav>
        )}
      </div>
    </>
  );
}

function NavLink({
  item,
  active,
  brandColor,
}: {
  item: NavItem;
  active: boolean;
  brandColor: string;
}) {
  const Icon = item.icon;
  return (
    <Link
      href={item.href}
      className={`pl-nav-link${active ? " active" : ""}`}
      style={active ? { backgroundColor: `${brandColor}22`, color: brandColor } : undefined}
    >
      <Icon className="pl-nav-icon" />
      {item.label}
    </Link>
  );
}
